# Complete solution: TDD implementation of a Stack with full test coverage
import pytest
from typing import TypeVar, Generic

T = TypeVar('T')

class Stack(Generic[T]):
    """A LIFO data structure with O(1) push, pop, peek."""

    def __init__(self) -> None:
        self._items: list[T] = []

    def push(self, item: T) -> None:
        """Add item to top."""
        self._items.append(item)

    def pop(self) -> T:
        """Remove and return top item. Raises IndexError if empty."""
        self._check_not_empty('pop')
        return self._items.pop()

    def peek(self) -> T:
        """Return top item without removing. Raises IndexError if empty."""
        self._check_not_empty('peek')
        return self._items[-1]

    def is_empty(self) -> bool:
        return len(self._items) == 0

    def size(self) -> int:
        return len(self._items)

    def _check_not_empty(self, op: str) -> None:
        if self.is_empty():
            raise IndexError(f"Cannot {op} from empty stack")

# Tests
