        stack.push(1)
        stack.push(2)
        assert stack.size() == 2

class TestStackPop:
    def test_pop_returns_last(self, stack):
        stack.push(1)
        stack.push(2)
        assert stack.pop() == 2

    def test_pop_empty_raises(self, stack):
        with pytest.raises(IndexError, match='pop'):
            stack.pop()

    def test_pop_lifo_order(self, stack):
        for i in range(5):
            stack.push(i)
        assert [stack.pop() for _ in range(5)] == [4, 3, 2, 1, 0]

class TestStackEdgeCases:
    def test_peek_does_not_remove(self, stack):
        stack.push(42)
        assert stack.peek() == 42
        assert stack.size() == 1

    def test_is_empty_true(self, stack):
        assert stack.is_empty() is True

    def test_is_empty_after_push(self, stack):
        stack.push(1)
        assert stack.is_empty() is False

    @pytest.mark.parametrize('items,expected_size', [
        ([], 0),
        ([1], 1),
        ([1, 2, 3], 3),
        (list(range(100)), 100),
    ])
    def test_size_parametrized(self, stack, items, expected_size):
        for item in items:
            stack.push(item)
        assert stack.size() == expected_size
